import React from 'react';

/**
 * A helper component that provides a basic accessible page structure with common landmarks.
 * This component ensures that all content passed to it is contained within appropriate
 * ARIA landmarks, addressing the Axe violation: "region".
 *
 * It includes a header, navigation, main content area, and footer.
 *
 * @param {object} props
 * @param {React.ReactNode} props.children - The main content of the page.
 * @param {string} [props.pageTitle='Page Title'] - The title for the page, displayed as the H1.
 */
const AiAccessibilityHelper = ({ children, pageTitle = 'Page Title' }) => {
  return (
    <>
      <header role="banner">
        {/* FIX: Added an H1 element to resolve 'page-has-heading-one' Axe violation */}
        <h1>{pageTitle}</h1>
        <nav aria-label="Main navigation">
          {/* Example navigation links */}
          <ul>
            <li><a href="#main-content">Skip to main content</a></li>
            <li><a href="/">Home</a></li>
            <li><a href="/about">About</a></li>
          </ul>
        </nav>
      </header>
      <main id="main-content" role="main">
        {children}
      </main>
      <footer role="contentinfo">
        <p>&copy; {new Date().getFullYear()} My Accessible App</p>
      </footer>
    </>
  );
};

export default AiAccessibilityHelper;

